# Each stage is a plain Python function.
# Input: iterable of records. Output: iterable of processed records.

def extract(filepath: str):
    """Stage 1: Read raw records from a CSV file."""
    import csv
    with open(filepath, newline="") as f:
        reader = csv.DictReader(f)
        for row in reader:
            yield row  # Yield one record at a time — memory efficient

def validate(records):
    """Stage 2: Drop records that are missing required fields."""
    for record in records:
        if record.get("email") and record.get("name"):
            yield record
        else:
            print(f"Skipping invalid record: {record}")

def transform(records):
    """Stage 3: Normalize and clean each record."""
    for record in records:
        yield {
            "name": record["name"].strip().title(),
            "email": record["email"].strip().lower(),
            "age": int(record.get("age", 0)),
        }

def load(records, output_path: str):
    """Stage 4: Write processed records to a JSON file."""
    import json
    results = list(records)  # Consume the generator
    with open(output_path, "w") as f:
        json.dump(results, f, indent=2)
    print(f"Loaded {len(results)} records to {output_path}")

import logging

logging.basicConfig(level=logging.INFO, format="%(asctime)s %(levelname)s %(message)s")
logger = logging.getLogger(__name__)

def validate(records):
    skipped = 0
    for record in records:
        if record.get("email") and record.get("name"):
            yield record
        else:
            skipped += 1
            logger.warning("Skipping record missing required fields: %s", record)
    logger.info("Validation complete. Skipped %d records.", skipped)

