from pydantic import BaseModel, EmailStr, validator

class UserRecord(BaseModel):
    name: str
    email: EmailStr
    age: int

    @validator("name")
    def name_not_empty(cls, v):
        assert v.strip(), "Name must not be empty"
        return v.strip().title()

def validate(records):
    for raw in records:
        try:
            yield UserRecord(**raw).dict()
        except Exception as e:
            logger.warning("Validation failed: %s — %s", raw, e)

def load_in_batches(records, conn, batch_size=1000):
    batch = []
    for record in records:
        batch.append(record)
        if len(batch) >= batch_size:
            conn.executemany("INSERT INTO ...", batch)
            batch.clear()
    if batch:  # Flush remaining
        conn.executemany("INSERT INTO ...", batch)
